CREATE TABLE IF NOT EXISTS specialist_service ( id VARCHAR(36) PRIMARY KEY, specialist_id VARCHAR(36) NOT NULL, title VARCHAR(255) NOT NULL, description TEXT, price INTEGER NOT NULL, currency VARCHAR(8) NOT NULL, active BOOLEAN NOT NULL,
CONSTRAINT fk_specialist_service_profile FOREIGN KEY (specialist_id) REFERENCES specialist_profile(id) ON DELETE CASCADE );
CREATE INDEX IF NOT EXISTS idx_service_specialist ON specialist_service (specialist_id);
CREATE INDEX IF NOT EXISTS idx_service_active ON specialist_service (active);
